var e=[{id:`L2_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`......끝난 건가?`,JPN:`……終わったか？`,ENG:`...Is it over?`,TWN:`……結束了嗎？`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`어이, 괜찮나? 정신 차려!`,JPN:`おい、大丈夫か？　しっかりしろ！`,ENG:`Hey, you okay? Wake up!`,TWN:`喂，沒事吧？振作一點！`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`이거......`,JPN:`これ……`,ENG:`Well...`,TWN:`這……`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`하하하하!`,JPN:`はははは！`,ENG:`Hahahaha...`,TWN:`哈哈哈哈！`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`침식체 놈들... 왜 이렇게 강한 거야?`,JPN:`侵食体のやつら……、何でこんなに強いの？`,ENG:`Why are these C.O.'s... so damn strong?`,TWN:`這些侵蝕體混蛋……為什麼這麼強？`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`......살아는 있는 모양이군.`,JPN:`……生きてはいるようだな。`,ENG:`I guess you're still breathing.`,TWN:`……它們好像還活著。`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`빨리 도망가자고.`,JPN:`早く逃げよう。`,ENG:`Let’s get out of here.`,TWN:`快點逃吧。`},stage:{bg:`NEWTOWN`,slots:{L:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`뭐야? 방금 다 처리했는데?`,JPN:`え？さっき全部倒したのに？`,ENG:`What? We just got rid of them all!`,TWN:`幹嘛？剛不是都解決了？`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`아무래도 방금 건 정찰꾼들이었나 보군.`,JPN:`さっきのやつらは偵察兵だったようだ。`,ENG:`They must’ve been just the recon.`,TWN:`看來剛才的是偵察兵。`},stage:{bg:`NEWTOWN`,slots:{L:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`정찰? 그런 것까지 하는 놈들이 있단 말야?`,JPN:`偵察？　あいつら、そんなこともできるのか？`,ENG:`Recon? They do that now?`,TWN:`偵察？ 那些傢伙連這都會幹啊？`},stage:{bg:`NEWTOWN`,slots:{L:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`그런 건 들어 본 적도 없다고!`,JPN:`偵察する侵食体なんて、聞いたことねえぞ！`,ENG:`I've never heard of such a thing!`,TWN:`從沒聽說過！`},stage:{bg:`NEWTOWN`,slots:{L:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`내가 알 게 뭐야?! 저 안쪽에 그런 놈들이 있나 보지!!`,JPN:`俺だって初めて見た！　あの奥には、そういったやつらがいるんだ！！`,ENG:`What do I know? I guess these guys are a little different!`,TWN:`我怎麼知道？！我只是看那些傢伙好像在這麼做而已！！`},stage:{bg:`NEWTOWN`,slots:{L:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`아무튼, 통신은 어떻게 됐어?`,JPN:`とにかく、通信はどうなった？`,ENG:`Anyway, how’s the comms coming along?`,TWN:`總之，通信怎麼樣了？`},stage:{bg:`NEWTOWN`,slots:{L:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`어이, 운전병?`,JPN:`おい、通信兵？`,ENG:`Hey, driver!`,TWN:`嘿，運輸兵？`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`어이! 괜찮나?!`,JPN:`おい！　大丈夫か！？`,ENG:`Hey! You alright?`,TWN:`喂，沒事吧？！`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`......틀렸어.`,JPN:`……ダメ。`,ENG:`We're screwed.`,TWN:`……沒救了。`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`운전병은 죽었어. 통신기는 반응이 없고.`,JPN:`通信兵は死んだわ。通信機も反応がない。`,ENG:`The driver’s dead. And nothing from the communicator.`,TWN:`運輸兵死了，接收器也沒有反應。`},stage:{bg:`NEWTOWN`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};